import{_ as e,o as a,c as i,a0 as n}from"./chunks/framework.DvNw9GNH.js";const c=JSON.parse('{"title":"🛰️ Bunti vs. The TUI Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"comparison.md","filePath":"comparison.md"}'),r={name:"comparison.md"};function l(s,t,o,d,h,u){return a(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="🛰️-bunti-vs-the-tui-ecosystem" tabindex="-1">🛰️ Bunti vs. The TUI Ecosystem <a class="header-anchor" href="#🛰️-bunti-vs-the-tui-ecosystem" aria-label="Permalink to &quot;🛰️ Bunti vs. The TUI Ecosystem&quot;">​</a></h1><p>Bunti is a high-performance, functional TUI engine built for the age of Bun. This document outlines how it compares to established standards in other languages and why it represents a new &quot;Surgical&quot; standard for terminal development.</p><h2 id="🏁-comparison-matrix" tabindex="-1">🏁 Comparison Matrix <a class="header-anchor" href="#🏁-comparison-matrix" aria-label="Permalink to &quot;🏁 Comparison Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;"><strong>Bunti</strong> (Bun)</th><th style="text-align:left;"><strong>Ink</strong> (TS/Node)</th><th style="text-align:left;"><strong>Ratatui</strong> (Rust)</th><th style="text-align:left;"><strong>Lipgloss</strong> (Go)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Paradigm</strong></td><td style="text-align:left;">Functional DSL</td><td style="text-align:left;">React (JSX)</td><td style="text-align:left;">Immediate Mode</td><td style="text-align:left;">Utility-First</td></tr><tr><td style="text-align:left;"><strong>API Style</strong></td><td style="text-align:left;">Scoped Closures</td><td style="text-align:left;">Hooks/JSX</td><td style="text-align:left;">Builder Pattern</td><td style="text-align:left;">Fluent Strings</td></tr><tr><td style="text-align:left;"><strong>Rendering</strong></td><td style="text-align:left;">Double-Buffered Diff</td><td style="text-align:left;">Virtual DOM</td><td style="text-align:left;">Double-Buffered Diff</td><td style="text-align:left;">Full-Frame Swap</td></tr><tr><td style="text-align:left;"><strong>Performance</strong></td><td style="text-align:left;">60-120 FPS</td><td style="text-align:left;">30-60 FPS</td><td style="text-align:left;">120+ FPS</td><td style="text-align:left;">60 FPS</td></tr><tr><td style="text-align:left;"><strong>Width-Aware</strong></td><td style="text-align:left;">Yes (Native)</td><td style="text-align:left;">Yes</td><td style="text-align:left;">Yes</td><td style="text-align:left;">Yes</td></tr><tr><td style="text-align:left;"><strong>Dependencies</strong></td><td style="text-align:left;">Zero</td><td style="text-align:left;">High (React)</td><td style="text-align:left;">Low</td><td style="text-align:left;">Low</td></tr></tbody></table><hr><h2 id="🏗️-architectural-advantages" tabindex="-1">🏗️ Architectural Advantages <a class="header-anchor" href="#🏗️-architectural-advantages" aria-label="Permalink to &quot;🏗️ Architectural Advantages&quot;">​</a></h2><h3 id="_1-the-scoped-closure-pattern" tabindex="-1">1. The Scoped Closure Pattern <a class="header-anchor" href="#_1-the-scoped-closure-pattern" aria-label="Permalink to &quot;1. The Scoped Closure Pattern&quot;">​</a></h3><p>Unlike <strong>Ink</strong>, which brings the heavy overhead of the React reconciler to the terminal, Bunti uses <strong>Scoped Closures with Contextual Capabilities</strong>. This gives you the same &quot;declarative&quot; feel but runs on a lightweight functional core. There is no Virtual DOM—only a surgical diff between two memory buffers.</p><h3 id="_2-double-buffered-diffing" tabindex="-1">2. Double-Buffered Diffing <a class="header-anchor" href="#_2-double-buffered-diffing" aria-label="Permalink to &quot;2. Double-Buffered Diffing&quot;">​</a></h3><p>Inspired by <strong>Ratatui</strong> and <strong>Notcurses</strong>, Bunti maintains a Front and Back buffer. Instead of redrawing the whole screen (which causes flickering), Bunti calculates the &quot;damage&quot; and only sends the changed cells to the terminal. This is critical for high-fidelity animations and low-latency SSH sessions.</p><h3 id="_3-bun-native-directwriter" tabindex="-1">3. Bun-Native DirectWriter <a class="header-anchor" href="#_3-bun-native-directwriter" aria-label="Permalink to &quot;3. Bun-Native DirectWriter&quot;">​</a></h3><p>Bunti leverages <code>Bun.stdout.writer()</code> to bypass the traditional Node.js stream overhead. Combined with our diffing engine, Bunti achieves extreme throughput with near-zero CPU usage.</p><h3 id="_4-emoji-nerd-font-correctness" tabindex="-1">4. Emoji &amp; Nerd Font Correctness <a class="header-anchor" href="#_4-emoji-nerd-font-correctness" aria-label="Permalink to &quot;4. Emoji &amp; Nerd Font Correctness&quot;">​</a></h3><p>Bunti treats character width as a first-class citizen using <code>Bun.stringWidth</code>. It automatically handles the &quot;Jagged Border&quot; problem by tracking wide-character placeholders in the buffer, ensuring your layouts never cave in.</p><h2 id="🎯-the-bunti-philosophy" tabindex="-1">🎯 The Bunti Philosophy <a class="header-anchor" href="#🎯-the-bunti-philosophy" aria-label="Permalink to &quot;🎯 The Bunti Philosophy&quot;">​</a></h2><p>Bunti is designed for <strong>Surgical Engineering</strong>. We prioritize:</p><ul><li><strong>Zero Bloat</strong>: Small, functional traits instead of heavy classes.</li><li><strong>High Signal</strong>: Scoped APIs that provide only what you need.</li><li><strong>Fidelity</strong>: 60FPS visuals with perfect Unicode alignment.</li></ul>',17)])])}const f=e(r,[["render",l]]);export{c as __pageData,f as default};
